   479→// ── Search snippet helpers ─────────────────────────────────────────────────────
   480→
   481→function extractMatchTerms(snippet: string): string[] {
   482→  const terms: string[] = [];
   483→  const re = /«([^»]+)»/g;
   484→  let m: RegExpExecArray | null;
   485→  while ((m = re.exec(snippet)) !== null) terms.push(m[1]);
   486→  return [...new Set(terms)];
   487→}
   488→
   489→// ── Source log event ID extractor ─────────────────────────────────────────────
   490→
   491→function getItemSourceIds(item: RenderItem): number[] {
   492→  if (item.kind === "event") {
   493→    const ids = item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   494→    if (item.event._extraSourceLogEventIds) ids.push(...item.event._extraSourceLogEventIds);
   495→    return ids;
   496→  }
   497→  if (item.kind === "claudeTurn") {
   498→    const ids: number[] = [];
   499→    for (const group of item.toolGroups) {
   500→      for (const tool of group) {
   501→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   502→        if (tool.pre._extraSourceLogEventIds) ids.push(...tool.pre._extraSourceLogEventIds);
   503→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   504→        if (tool.post?._extraSourceLogEventIds) ids.push(...tool.post._extraSourceLogEventIds);
   505→      }
   506→    }
   507→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   508→    if (item.stop?._extraSourceLogEventIds) ids.push(...item.stop._extraSourceLogEventIds);
   509→    return ids;
   510→  }
   511→  return [];
   512→}
