   514→export function SessionDetail() {
   515→  const navigate = useNavigate();
   516→  const { sessionId } = useParams<{ sessionId: string }>();
   517→  const [searchParams] = useSearchParams();
   518→  const location = useLocation();
   519→  const targetLogEventId = searchParams.get("logEventId") ? parseInt(searchParams.get("logEventId")!) : null;
   520→  const searchSnippet = (location.state as { snippet?: string; contentType?: string } | null)?.snippet ?? null;
   521→  const searchContentType = (location.state as { snippet?: string; contentType?: string } | null)?.contentType ?? null;
   522→  const [highlightActive, setHighlightActive] = useState(false);
   523→  const scrolledRef = useRef(false);
