   579→        applyCheckpoints(logEvs, checkpoints);
   580→        setError(null);
   581→      })
   582→      .catch((err: unknown) => setError(String(err)))
   583→      .finally(() => setLoading(false));
   584→  }, [id]);
   585→
   586→  // Live updates: re-fetch checkpoints and log events when the server broadcasts a change
   587→  useEffect(() => {
   588→    return subscribeToUpdates(() => {
   589→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
   590→        .then(([logEvs, checkpoints]) => applyCheckpoints(logEvs, checkpoints))
   591→        .catch(() => undefined);
   592→    });
