   621→        const targetRect = el.getBoundingClientRect();
   622→        const vpRect = viewport.getBoundingClientRect();
   623→        const scrollTop = viewport.scrollTop + targetRect.top - vpRect.top - viewport.clientHeight / 2 + targetRect.height / 2 + 16;
   624→        viewport.scrollTo({ top: Math.max(0, scrollTop), behavior: "smooth" });
   625→      });
   626→    }, 250);
   627→    return () => clearTimeout(t);
   628→  }, [highlightActive, targetLogEventId]);
   629→
