    97→      for (const m of allMetas) {
    98→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
    99→      }
   100→
   101→      // Git user per checkpoint (from commit author stored at index time)
   102→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   103→      const cpUserRows = allCheckpointIds.length > 0
