   120→      // Min/max LogEvent timestamps per session
   121→      const times = await db.logEvent.groupBy({
   122→        by: ["sessionId"],
   123→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   124→        _min: { timestamp: true },
   125→        _max: { timestamp: true },
   126→      });
   127→      const timeMap = new Map(
   128→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   129→      );
   130→
   131→      // First cwd per session
   132→      const cwdRows = await db.logEvent.findMany({
   133→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   134→        distinct: ["sessionId"],
   135→        orderBy: { id: "asc" },
   136→        select: { sessionId: true, cwd: true },
   137→      });
   138→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   139→
   140→      const result: SessionResponse[] = allIds.map((sessionId) => {
   141→        const cp     = cpMap.get(sessionId) ?? null;
   142→        const shadow = shadowMap.get(sessionId) ?? null;
   143→        const t      = timeMap.get(sessionId);
   144→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   145→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   146→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   147→        return {
   148→          sessionId,
   149→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   150→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   151→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   152→          repoRoot:        repoDir ?? null,
