   154→          parentSessionId: null,
   155→          childSessionIds: [],
   156→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   157→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   158→          prompt:          shadow?.prompt ?? null,
   159→          summary:         null,
