   212→        cwd:             firstEvent?.cwd ?? shadow?.cwd ?? "",
   213→        repoRoot:        repoDir ?? null,
   214→        repoName:        repoName,
   215→        parentSessionId: null,
   216→        childSessionIds: [],
   217→        gitUserName:     cpMeta?.gitUserName ?? gitUser.name,
   218→        gitUserEmail:    cpMeta?.gitUserEmail ?? gitUser.email,
   219→        prompt:          shadow?.prompt ?? null,
   220→        summary:         null,
