   228→    }
   229→  });
   230→
   231→  // GET /api/sessions/:id/overview
   232→  app.get("/api/sessions/:id/overview", async (req, res) => {
   233→    try {
   234→      const overview = await db.interactionOverview.findUnique({
   235→        where: { sessionId: req.params.id },
   236→      });
   237→      if (!overview) {
   238→        res.status(404).json({ error: "No overview for this session" });
   239→        return;
