   375→
   376→      // Group sessions by checkpointId
   377→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   378→      for (const s of sessions) {
   379→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   380→        arr.push(s);
   381→        sessionsByCheckpoint.set(s.checkpointId, arr);
