   383→
   384→      res.json(checkpoints.map((c) => {
   385→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   386→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   387→        const latestCreatedAt = cpSessions
   388→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   389→          .map((s) => s.createdAt)
   390→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   391→        return {
   392→          id:               c.id,
   393→          checkpointId:     c.checkpointId,
   394→          cliVersion:       c.cliVersion,
   395→          strategy:         c.strategy,
   396→          branch:           c.branch,
   397→          checkpointsCount: c.checkpointsCount,
   398→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   399→          tokenUsage: c.tokenUsage ? {
   400→            inputTokens:         c.tokenUsage.inputTokens,
   401→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   402→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   403→            outputTokens:        c.tokenUsage.outputTokens,
   404→            apiCallCount:        c.tokenUsage.apiCallCount,
   405→          } : null,
   406→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   407→          sessionCount:  cpSessions.length,
   408→          summary: summary ? mapV2Summary(summary) : null,
   409→        };
   410→      }));
   411→    } catch (err) {
   412→      res.status(500).json({ error: String(err) });
   413→    }
   414→  });
