#!/usr/bin/env node
// Prevent any git subprocess from prompting for credentials or contacting remotes.
// SSH_AUTH_SOCK="" disables the macOS Keychain SSH agent GUI dialog.
// gc.auto=0 and fetch.recurseSubmodules=off prevent background network operations.
process.env.GIT_TERMINAL_PROMPT = "0";
process.env.GIT_SSH_COMMAND = "ssh -o BatchMode=yes";
process.env.SSH_AUTH_SOCK = "";
process.env.GIT_CONFIG_COUNT = String(Number(process.env.GIT_CONFIG_COUNT ?? 0) + 2);
const base = Number(process.env.GIT_CONFIG_COUNT) - 2;
process.env[`GIT_CONFIG_KEY_${base}`]   = "gc.auto";
process.env[`GIT_CONFIG_VALUE_${base}`] = "0";
process.env[`GIT_CONFIG_KEY_${base + 1}`]   = "fetch.recurseSubmodules";
process.env[`GIT_CONFIG_VALUE_${base + 1}`] = "off";

