const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
let checkpointPoller: ReturnType<typeof setInterval> | null = null;

if (repoDir) {
  const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
  mkdirSync(join(repoDir, ".gossamer"), { recursive: true });

  const GIT_LOCAL_ENV = { ...process.env, GIT_TERMINAL_PROMPT: "0", GIT_SSH_COMMAND: "ssh -o BatchMode=yes" };

  // Ensure worktree exists (reuse across restarts)
  if (!existsSync(WORKTREE_PATH)) {
    try {
      // Prune stale worktree registration first, then re-add
      execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe", env: GIT_LOCAL_ENV });
      execSync(
        `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} refs/heads/${CHECKPOINT_BRANCH}`,
        { stdio: "pipe", env: GIT_LOCAL_ENV },
      );
      process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
    } catch (err) {
      process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
    }
  }

  const GIT_LOCAL_ENV = { ...process.env, GIT_TERMINAL_PROMPT: "0", GIT_SSH_COMMAND: "ssh -o BatchMode=yes" };

  const runIndex = async () => {
    if (!existsSync(WORKTREE_PATH)) return;
    // Reset worktree to latest local branch tip — use refs/heads/ to prevent remote resolution
    try {
      await exec(
        `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard refs/heads/${CHECKPOINT_BRANCH}`,
        { env: GIT_LOCAL_ENV },
      );

