// Ensure worktree exists (reuse across restarts)
if (!existsSync(WORKTREE_PATH)) {
  try {
    // Prune stale worktree registration first, then re-add.
    // --no-track ensures the worktree branch is never wired to a remote.
    execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe", env: GIT_LOCAL_ENV });
    execSync(
      `git -C ${JSON.stringify(repoDir)} worktree add --no-track ${JSON.stringify(WORKTREE_PATH)} refs/heads/${CHECKPOINT_BRANCH}`,
      { stdio: "pipe", env: GIT_LOCAL_ENV },
    );
    // Remove any upstream tracking the branch may have had in the main repo
    try {
      execSync(`git -C ${JSON.stringify(repoDir)} branch --unset-upstream ${CHECKPOINT_BRANCH}`, { stdio: "pipe", env: GIT_LOCAL_ENV });
    } catch { /* fine if there was no upstream */ }
    process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
  } catch (err) {
    process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
  }
}

