    try {
      await exec(`git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`, { timeout: 10_000 });
      await exec(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard origin/${CHECKPOINT_BRANCH}`);
