                {(diffStats ?? checkpoint.filesTouched.map((f) => ({ path: f, additions: 0, deletions: 0 }))).map(({ path, additions, deletions }) => (
                  <Group key={path} gap={8} wrap="nowrap">
                    <Text size="xs" ff="monospace" style={{ flex: 1, minWidth: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{path}</Text>
                    <Group gap={4} style={{ flexShrink: 0 }}>
                      {additions > 0 && <Text size="xs" c="teal" ff="monospace" fw={600}>+{additions}</Text>}
                      {deletions > 0 && <Text size="xs" c="red" ff="monospace" fw={600}>-{deletions}</Text>}
                    </Group>
                  </Group>
                ))}
              </Box>
            </SectionBlock>
          )}

          <UnstyledButton
            onClick={onPress}
            style={{ alignSelf: "flex-start", padding: "5px 10px", borderRadius: 4, border: "1px solid var(--mantine-color-teal-3)" }}
          >
            <Text size="xs" c="teal" ff="monospace">Open checkpoint →</Text>
          </UnstyledButton>
        </Box>
      </Collapse>
    </Box>
    </Box>
  );
}

