          {stop && <TimeAgo iso={stop.timestamp} />}
        </Group>
        {thinking && (
          <Box mb={6} id={thinkingUuid ?? (thinkingLogEventId != null ? `log-event-${thinkingLogEventId}` : undefined)}>
