              gap={6}
              mb={4}
              style={{ cursor: "pointer" }}
              onClick={() => setThinkingExpanded((v) => !v)}
            >
              <Text size="xs" c="dimmed" fs="italic">thinking {thinkingExpanded ? "▲" : "▼"}</Text>
            </Group>
            <Collapse in={thinkingExpanded}>
