            border: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4))",
            borderRadius: "2px 14px 14px 14px",
            padding: "12px 16px",
            marginBottom: toolGroups.length > 0 ? 8 : 0,
          }}>
