          </Box>
        )}
        {toolGroups.length > 0 && (
          <Box id={toolsUuid ?? (toolsLogEventId != null ? `log-event-${toolsLogEventId}` : undefined)}>
            <Group
              gap={6}
              mb={4}
              style={{ cursor: "pointer" }}
              onClick={() => setToolsExpanded((v) => !v)}
            >
