   362→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   363→      continue;
   364→    }
   365→    raw.push({ kind: "event", event });
   366→  }
   367→
   368→  const isGroupable = (item: RawItem) =>
   369→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   370→
   371→  const result: DisplayItem[] = [];
   372→  let i = 0;
   373→  while (i < raw.length) {
   374→    if (isGroupable(raw[i])) {
   375→      const group: ToolUseData[] = [];
   376→      while (i < raw.length && isGroupable(raw[i])) {
   377→        const item = raw[i];
   378→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   379→        i++;
   380→      }
   381→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   382→    } else {
   383→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   384→      i++;
   385→    }
   386→  }
   387→  return result;
   388→}
