   536→// ── Search snippet helpers ─────────────────────────────────────────────────────
   537→
   538→function extractMatchTerms(snippet: string): string[] {
   539→  const terms: string[] = [];
   540→  const re = /«([^»]+)»/g;
   541→  let m: RegExpExecArray | null;
   542→  while ((m = re.exec(snippet)) !== null) terms.push(m[1]);
   543→  return [...new Set(terms)];
   544→}
   545→
   546→// ── Source log event ID extractor ─────────────────────────────────────────────
   547→
   548→function getItemSourceIds(item: RenderItem): number[] {
   549→  if (item.kind === "event") {
   550→    const ids = item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   551→    if (item.event._extraSourceLogEventIds) ids.push(...item.event._extraSourceLogEventIds);
   552→    return ids;
   553→  }
   554→  if (item.kind === "claudeTurn") {
   555→    const ids: number[] = [];
   556→    for (const group of item.toolGroups) {
   557→      for (const tool of group) {
   558→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   559→        if (tool.pre._extraSourceLogEventIds) ids.push(...tool.pre._extraSourceLogEventIds);
   560→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   561→        if (tool.post?._extraSourceLogEventIds) ids.push(...tool.post._extraSourceLogEventIds);
   562→      }
   563→    }
   564→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   565→    if (item.stop?._extraSourceLogEventIds) ids.push(...item.stop._extraSourceLogEventIds);
   566→    return ids;
   567→  }
   568→  return [];
   569→}
