   571→export function SessionDetail() {
   572→  const navigate = useNavigate();
   573→  const { sessionId } = useParams<{ sessionId: string }>();
   574→  const [searchParams] = useSearchParams();
   575→  const location = useLocation();
   576→  const targetLogEventId = searchParams.get("logEventId") ? parseInt(searchParams.get("logEventId")!) : null;
   577→  const searchSnippet = (location.state as { snippet?: string; contentType?: string } | null)?.snippet ?? null;
   578→  const searchContentType = (location.state as { snippet?: string; contentType?: string } | null)?.contentType ?? null;
   579→  const [highlightActive, setHighlightActive] = useState(false);
   580→  const scrolledRef = useRef(false);
   581→  const viewportRef = useRef<HTMLDivElement>(null);
   582→  const logEventsRef = useRef<LogEventItem[]>([]);
   583→  const [session, setSession] = useState<Session | null>(null);
   584→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   585→  const [items, setItems] = useState<RenderItem[]>([]);
   586→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   587→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   588→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   589→  const [spawning, setSpawning] = useState(false);
   590→  const [loading, setLoading] = useState(true);
   591→  const [error, setError] = useState<string | null>(null);
   592→
   593→  const id = sessionId!;
   594→  const { setCrumbs } = useBreadcrumb();
   595→
   596→  function applyCheckpoints(logEvs: LogEventItem[], checkpoints: SessionCheckpoint[]) {
   597→    const grouped = groupEvents(logEventsToEvents(logEvs));
   598→    const merged: DisplayItem[] = [];
   599→    let cpIdx = 0;
   600→    const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   601→    const latest = sortedCps[sortedCps.length - 1] ?? null;
   602→    setLatestCheckpoint(latest);
   603→    setOpenItems(latest?.summary?.openItems ?? []);
   604→
   605→    for (const item of grouped) {
   606→      const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   607→      while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   608→        merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   609→      }
   610→      merged.push(item);
   611→    }
   612→    while (cpIdx < sortedCps.length) merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   613→    setItems(groupClaudeTurns(merged));
   614→  }
   615→
   616→  // Initial load
   617→  useEffect(() => {
   618→    Promise.all([fetchSession(id), fetchLogEvents(id), fetchSessionCheckpoints(id)])
   619→      .then(([s, logEvs, checkpoints]) => {
   620→        logEventsRef.current = logEvs;
   621→        setSession(s);
   622→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   623→        const repo = s.repoName ?? null;
   624→        const shortId = s.sessionId.slice(0, 8) + "…";
   625→        if (user) {
   626→          setUserInfo({
   627→            name: s.gitUserName ?? user,
   628→            avatarUrl: s.gitUserName ? `https://github.com/${s.gitUserName}.png?size=40` : undefined,
   629→          });
   630→        }
   631→        setCrumbs([
   632→          ...(user ? [{ label: user, path: "/" }] : []),
   633→          ...(repo ? [{ label: repo, path: "/" }] : []),
   634→          { label: shortId },
   635→        ]);
   636→        applyCheckpoints(logEvs, checkpoints);
   637→        setError(null);
   638→      })
   639→      .catch((err: unknown) => setError(String(err)))
   640→      .finally(() => setLoading(false));
   641→  }, [id]);
   642→
   643→  // Live updates: re-fetch checkpoints and log events when the server broadcasts a change
   644→  useEffect(() => {
   645→    return subscribeToUpdates(() => {
   646→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
   647→        .then(([logEvs, checkpoints]) => applyCheckpoints(logEvs, checkpoints))
   648→        .catch(() => undefined);
   649→    });
   650→  }, [id]);
   651→
   652→  // Step 1: activate highlight once items are loaded (triggers Collapse expand + mark rendering)
   653→  useEffect(() => {
   654→    if (targetLogEventId === null || items.length === 0 || scrolledRef.current) return;
   655→    const t = setTimeout(() => {
   656→      setHighlightActive(true);
   657→      scrolledRef.current = true;
   658→      setTimeout(() => setHighlightActive(false), 10000);
   659→    }, 150);
   660→    return () => clearTimeout(t);
   661→  }, [items, targetLogEventId]);
   662→
   663→  // Step 2: once highlightActive is true (marks rendered, Collapses expanding), scroll to first <mark>
   664→  useEffect(() => {
   665→    if (!highlightActive || targetLogEventId === null) return;
   666→    // Wait for Collapse animations (~200ms) to reach their final layout before measuring
   667→    const t = setTimeout(() => {
   668→      requestAnimationFrame(() => {
   669→        // Resolve UUID for the target logEventId, then find the most precise element
   670→        const uuid = logEventsRef.current.find((le) => le.id === targetLogEventId)?.uuid ?? null;
   671→        const el = (
   672→          (uuid ? document.getElementById(uuid) : null)
   673→          ?? document.getElementById(`log-event-${targetLogEventId}`)
   674→          ?? document.querySelector(`[data-log-event-id="${targetLogEventId}"]`)
   675→        ) as HTMLElement | null;
   676→        const viewport = viewportRef.current;
   677→        if (!el || !viewport) return;
   678→        const targetRect = el.getBoundingClientRect();
   679→        const vpRect = viewport.getBoundingClientRect();
   680→        const scrollTop = viewport.scrollTop + targetRect.top - vpRect.top - viewport.clientHeight / 2 + targetRect.height / 2 + 16;
   681→        viewport.scrollTo({ top: Math.max(0, scrollTop), behavior: "smooth" });
   682→      });
   683→    }, 250);
   684→    return () => clearTimeout(t);
   685→  }, [highlightActive, targetLogEventId]);
   686→
   687→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
   688→  if (error) return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   689→
   690→  return (
   691→    <ScrollArea style={{ flex: 1 }} viewportRef={viewportRef}>
   692→      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>
   693→      {session?.parentSessionId && (
   694→        <UnstyledButton
   695→          onClick={() => navigate(`/sessions/${session.parentSessionId}`, { state: { title: session.parentSessionId!.slice(0, 8) + "…" } })}
   696→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-blue-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-blue-2)", padding: "8px 14px" }}
   697→        >
   698→          <Text size="xs" c="blue">↑ Continuation of</Text>
   699→          <Text size="xs" c="blue" ff="monospace" fw={600} td="underline">{session.parentSessionId.slice(0, 8)}…</Text>
   700→        </UnstyledButton>
   701→      )}
   702→      {session?.childSessionIds?.map((childId) => (
   703→        <UnstyledButton
   704→          key={childId}
   705→          onClick={() => navigate(`/sessions/${childId}`, { state: { title: childId.slice(0, 8) + "…" } })}
   706→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-green-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-green-2)", padding: "8px 14px" }}
   707→        >
   708→          <Text size="xs" c="green">↓ Continued as</Text>
   709→          <Text size="xs" c="green" ff="monospace" fw={600} td="underline">{childId.slice(0, 8)}…</Text>
   710→        </UnstyledButton>
   711→      ))}
   712→
   713→      {latestCheckpoint?.summary && (
   714→        <Box style={{
   715→          borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   716→          padding: "16px 20px",
   717→          backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))",
   718→        }}>
   719→          <Text size="sm" fw={600} lh={1.5} mb={latestCheckpoint.summary.openItems?.length ? 12 : 0}>
   720→            {latestCheckpoint.summary.intent}
   721→          </Text>
   722→          {openItems.length > 0 && (
   723→            <Box>
   724→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={8} style={{ letterSpacing: 0.5 }}>
   725→                Open items
   726→              </Text>
   727→              {openItems.map((item, i) => {
   728→                const selectable = item.status === "open";
   729→                const statusColor = item.status === "complete" ? "teal" : item.status === "in_progress" ? "orange" : item.status === "na" ? "gray" : "blue";
   730→                const statusLabel = item.status === "in_progress" ? "in progress" : item.status === "na" ? "n/a" : item.status;
   731→                return (
   732→                  <Group key={item.id} gap={10} align="flex-start" mb={6} wrap="nowrap">
   733→                    {selectable ? (
   734→                      <Checkbox
   735→                        size="xs"
