    86→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
    87→  app.get("/api/sessions", async (_req, res) => {
    88→    try {
    89→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
    90→      const allMetas = await db.checkpointSessionMetadata.findMany({
    91→        select: {
    92→          sessionId: true,
    93→          checkpointId: true,
    94→          branch: true,
    95→          summary: { select: { intent: true } },
    96→        },
    97→        orderBy: { createdAt: "asc" },
    98→      });
    99→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   100→      for (const m of allMetas) {
   101→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   102→      }
   103→
   104→      // Git user per checkpoint (from commit author stored at index time)
   105→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   106→      const cpUserRows = allCheckpointIds.length > 0
   107→        ? await db.checkpointMetadata.findMany({
   108→            where: { checkpointId: { in: allCheckpointIds } },
   109→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   110→          })
   111→        : [];
   112→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   113→
   114→      const shadows = await db.shadowSession.findMany();
   115→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   116→
   117→      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
   118→      if (allIds.length === 0) {
   119→        res.json([]);
   120→        return;
   121→      }
   122→
   123→      // Min/max LogEvent timestamps per session
   124→      const times = await db.logEvent.groupBy({
   125→        by: ["sessionId"],
   126→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   127→        _min: { timestamp: true },
   128→        _max: { timestamp: true },
   129→      });
   130→      const timeMap = new Map(
   131→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   132→      );
   133→
   134→      // First cwd per session
   135→      const cwdRows = await db.logEvent.findMany({
   136→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   137→        distinct: ["sessionId"],
   138→        orderBy: { id: "asc" },
   139→        select: { sessionId: true, cwd: true },
   140→      });
   141→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   142→
   143→      const result: SessionResponse[] = allIds.map((sessionId) => {
   144→        const cp     = cpMap.get(sessionId) ?? null;
   145→        const shadow = shadowMap.get(sessionId) ?? null;
   146→        const t      = timeMap.get(sessionId);
   147→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   148→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   149→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   150→        return {
   151→          sessionId,
   152→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   153→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   154→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   155→          repoRoot:        repoDir ?? null,
   156→          repoName:        repoName,
   157→          parentSessionId: null,
   158→          childSessionIds: [],
   159→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   160→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   161→          prompt:          shadow?.prompt ?? null,
   162→          summary:         null,
   163→          keywords:        [],
   164→          branch:          cp?.branch ?? shadow?.gitBranch ?? null,
   165→          intent:          cp?.intent ?? null,
   166→          isLive:          shadow !== null,
   167→        };
   168→      });
   169→
   170→      result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   171→      res.json(result);
   172→    } catch (err) {
   173→      res.status(500).json({ error: String(err) });
   174→    }
   175→  });
