   542→  // POST /api/sessions/spawn
   543→  app.post("/api/sessions/spawn", async (req, res) => {
   544→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   545→    if (!prompt || typeof prompt !== "string") {
   546→      res.status(400).json({ error: "prompt is required" });
   547→      return;
   548→    }
   549→    try {
   550→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   551→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   552→      // Pass open item IDs and parent session so the SessionStart hook can link back
   553→      const envParts: string[] = [];
   554→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   555→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   556→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   557→      // Use AppleScript to open a new Terminal window running claude interactively
   558→      const script = [
   559→        `tell application "Terminal"`,
   560→        `  activate`,
   561→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   562→        `end tell`,
   563→      ].join("\n");
   564→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   565→      // Mark selected open items as in_progress
   566→      if (openItemIds?.length) {
   567→        await db.openItem.updateMany({
   568→          where: { id: { in: openItemIds } },
   569→          data: { status: "in_progress" },
   570→        });
   571→      }
   572→      res.json({ started: true });
   573→    } catch (err) {
   574→      res.status(500).json({ error: String(err) });
   575→    }
   576→  });
