   587→        ? await db.checkpointSessionMetadata.findMany({
   588→            where: { sessionId: { in: sessionIds } },
   589→            select: { sessionId: true, checkpointId: true },
   590→            distinct: ["sessionId"],
   591→            orderBy: { createdAt: "desc" },
   592→          })
   593→        : [];
   594→      const cpIds = [...new Set(sessionMetas.map((m) => m.checkpointId))];
   595→      const cpUsers = cpIds.length > 0
   596→        ? await db.checkpointMetadata.findMany({
   597→            where: { checkpointId: { in: cpIds } },
   598→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   599→          })
   600→        : [];
   601→      const cpUserMap = new Map(cpUsers.map((r) => [r.checkpointId, r]));
   602→      const sessionUserMap = new Map(sessionMetas.map((m) => {
   603→        const u = cpUserMap.get(m.checkpointId);
   604→        return [m.sessionId, { gitUserName: u?.gitUserName ?? null, gitUserEmail: u?.gitUserEmail ?? null }];
   605→      }));
   606→      res.json(results.map((r) => {
   607→        const u = sessionUserMap.get(r.sessionId);
   608→        return { ...r, gitUserName: u?.gitUserName ?? gitUser.name, gitUserEmail: u?.gitUserEmail ?? gitUser.email };
   609→      }));
   610→    } catch (err) {
   611→      // FTS5 MATCH errors (bad syntax) come back as exceptions
   612→      res.status(400).json({ error: String(err) });
   613→    }
   614→  });
   615→
   616→  // Create HTTP server and attach WebSocket server (shared port)
   617→  const httpServer = createServer(app);
   618→  const wss = new WebSocketServer({ server: httpServer });
   619→
   620→  // WebSocket change detection — poll every 2s, broadcast on new log events, checkpoints, or shadow sessions
   621→  let lastMaxLogEventId: number | null = null;
   622→  let lastMaxCheckpointId: number | null = null;
   623→  let lastMaxShadowSessionId: number | null = null;
   624→  const broadcast = () => {
   625→    const message = JSON.stringify({ type: "sessions_updated" });
   626→    for (const client of wss.clients) {
   627→      if (client.readyState === WebSocket.OPEN) {
   628→        client.send(message);
   629→      }
   630→    }
   631→  };
   632→  const poller = setInterval(async () => {
   633→    try {
   634→      const [latestLogEvent, latestCheckpoint, latestShadow] = await Promise.all([
   635→        db.logEvent.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   636→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   637→        db.shadowSession.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   638→      ]);
   639→      const curLogEvent   = latestLogEvent?.id   ?? null;
   640→      const curCheckpoint = latestCheckpoint?.id ?? null;
   641→      const curShadow     = latestShadow?.id     ?? null;
   642→      if (curLogEvent !== lastMaxLogEventId || curCheckpoint !== lastMaxCheckpointId || curShadow !== lastMaxShadowSessionId) {
   643→        lastMaxLogEventId   = curLogEvent;
   644→        lastMaxCheckpointId = curCheckpoint;
   645→        lastMaxShadowSessionId = curShadow;
   646→        broadcast();
   647→      }
   648→    } catch {
   649→      // Non-fatal polling error — keep running
   650→    }
   651→  }, 2000);
   652→
   653→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   654→
   655→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   656→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   657→
   658→  if (repoDir) {
   659→    const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
   660→    mkdirSync(join(repoDir, ".gossamer"), { recursive: true });
   661→
   662→    // Ensure worktree exists (reuse across restarts)
   663→    if (!existsSync(WORKTREE_PATH)) {
   664→      try {
   665→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   666→        execSync(
   667→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   668→          { stdio: "pipe" },
   669→        );
   670→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   671→      } catch (err) {
   672→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   673→      }
   674→    }
   675→
   676→    const runIndex = async () => {
   677→      if (!existsSync(WORKTREE_PATH)) return;
   678→      // Fetch to update remote tracking ref, then fast-forward local branch if possible.
   679→      // Always reset to the local branch tip so local-only commits are included.
   680→      try {
   681→        await exec(`git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`, { timeout: 10_000 });
   682→      } catch { /* remote unavailable — index local state */ }
   683→      try {
   684→        // Use refs/heads/ explicitly to always resolve to the local branch, never the remote tracking ref
   685→        await exec(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard refs/heads/${CHECKPOINT_BRANCH}`);
   686→      } catch { /* non-fatal */ }
   687→      try {
   688→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   689→        if (checkpoints > 0) {
   690→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   691→          broadcast();
   692→        }
   693→      } catch { /* non-fatal */ }
   694→    };
   695→
   696→    void runIndex();
   697→    checkpointPoller = setInterval(runIndex, 30_000);
   698→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   699→  }
   700→
   701→  // ── Shadow branch indexer ──────────────────────────────────────────────────
   702→
   703→  let shadowPoller: ReturnType<typeof setInterval> | null = null;
   704→
   705→  if (repoDir) {
   706→    const runShadowIndex = async () => {
   707→      try {
   708→        const { sessions } = await indexAllShadowBranches(db, repoDir);
   709→        if (sessions > 0) broadcast();
   710→      } catch { /* non-fatal */ }
   711→    };
   712→
   713→    void runShadowIndex();
   714→    shadowPoller = setInterval(runShadowIndex, 5_000);
   715→    process.stderr.write(`shadow indexer: polling every 5s (repo: ${repoDir})\n`);
   716→  }
   717→
   718→  // Graceful shutdown
   719→  const shutdown = () => {
   720→    clearInterval(poller);
   721→    if (checkpointPoller) clearInterval(checkpointPoller);
   722→    if (shadowPoller) clearInterval(shadowPoller);
   723→    httpServer.close();
   724→    process.exit(0);
   725→  };
   726→  process.on("SIGINT", shutdown);
   727→  process.on("SIGTERM", shutdown);
   728→
   729→  await new Promise<void>((resolve) => {
   730→    httpServer.listen(port, () => {
   731→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   732→      resolve();
   733→    });
   734→  });
   735→}
