// Returned by GET /api/sessions/:id/checkpoints — session-scoped view of a checkpoint
export interface SessionCheckpoint {
  checkpointId: string;
  branch: string | null;
  cliVersion: string | null;
  filesTouched: string[];
  tokenUsage: TokenUsage | null;
