          <SectionBlock title="Files changed">
            <Box style={{ display: "flex", flexDirection: "column", gap: 3 }}>
              {diffStats === null ? (
                <Text size="xs" c="dimmed">Loading…</Text>
              ) : diffStats.length > 0 ? (
                diffStats.map(({ path, additions, deletions }) => (
                  <Group key={path} gap={8} wrap="nowrap">
                    <Text size="xs" ff="monospace" style={{ flex: 1, minWidth: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{path}</Text>
