  const reason = str(d.reason);
  const thinkingLogEventId = typeof d.thinkingLogEventId === "number" ? d.thinkingLogEventId : null;
  const thinkingUuid = typeof d.thinkingUuid === "string" ? d.thinkingUuid : null;
