// ── Unified diff parser + renderer ───────────────────────────────────────────

interface DiffLine {
  type: "added" | "removed" | "context" | "noNewline";
  content: string;
}

interface DiffHunk {
  header: string;
  lines: DiffLine[];
}

interface DiffFile {
  path: string;
  hunks: DiffHunk[];
}

function parseUnifiedDiff(patch: string): DiffFile[] {
  const files: DiffFile[] = [];
  const chunks = patch.split(/^diff --git /m).filter(Boolean);
  for (const chunk of chunks) {
    const lines = chunk.split("\n");
    let path = "";
    for (const line of lines) {
      if (line.startsWith("+++ b/")) { path = line.slice(6); break; }
      if (line.startsWith("+++ /dev/null")) { path = "(deleted)"; break; }
      if (line.startsWith("+++ ")) { path = line.slice(4); break; }
    }
    const hunks: DiffHunk[] = [];
    let cur: DiffHunk | null = null;
    for (const line of lines) {
      if (line.startsWith("@@ ")) {
        cur = { header: line, lines: [] };
        hunks.push(cur);
      } else if (cur) {
        if (line.startsWith("+"))       cur.lines.push({ type: "added",     content: line.slice(1) });
        else if (line.startsWith("-"))  cur.lines.push({ type: "removed",   content: line.slice(1) });
        else if (line.startsWith("\\")) cur.lines.push({ type: "noNewline", content: line });
        else if (line !== "")           cur.lines.push({ type: "context",   content: line.slice(1) });
      }
    }
    if (path || hunks.length > 0) files.push({ path, hunks });
  }
  return files;
}

function UnifiedDiffView({ patch }: { patch: string }) {
  const files = parseUnifiedDiff(patch);
  if (files.length === 0) return <Text size="xs" c="dimmed">Empty diff</Text>;

  return (
    <Box style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      {files.map((file, fi) => (
        <Box key={fi} style={{
          border: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
          borderRadius: 6,
          overflow: "hidden",
        }}>
          {/* File header */}
          <Box style={{
            padding: "5px 10px",
            backgroundColor: "light-dark(var(--mantine-color-gray-1), var(--mantine-color-dark-6))",
            borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
          }}>
            <Text size="xs" ff="monospace" fw={600} c="violet">{file.path}</Text>
          </Box>
          {/* Hunks */}
          {file.hunks.map((hunk, hi) => (
            <Box key={hi} style={{ overflowX: "auto" }}>
              {/* @@ header */}
              <Box style={{
                padding: "2px 10px",
                backgroundColor: "light-dark(var(--mantine-color-blue-0), rgba(59,130,246,0.08))",
                borderBottom: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-5))",
              }}>
                <Text size="xs" ff="monospace" c="dimmed" fs="italic">{hunk.header}</Text>
              </Box>
              {/* Lines */}
              {hunk.lines.map((line, li) => {
                const bg =
                  line.type === "added"   ? "light-dark(rgba(0,160,80,0.10), rgba(0,200,80,0.13))" :
                  line.type === "removed" ? "light-dark(rgba(220,50,50,0.09), rgba(220,60,60,0.18))" :
                  "transparent";
                const prefixColor =
                  line.type === "added" ? "var(--mantine-color-green-6)" :
                  line.type === "removed" ? "var(--mantine-color-red-6)" :
                  "transparent";
                const textColor =
                  line.type === "added"   ? "light-dark(var(--mantine-color-green-8), var(--mantine-color-green-3))" :
                  line.type === "removed" ? "light-dark(var(--mantine-color-red-8), var(--mantine-color-red-3))" :
                  line.type === "noNewline" ? "var(--mantine-color-dimmed)" :
                  "light-dark(var(--mantine-color-dark-8), var(--mantine-color-gray-1))";
                const prefix = line.type === "added" ? "+" : line.type === "removed" ? "-" : " ";
                return (
                  <Box key={li} style={{ display: "flex", backgroundColor: bg, minWidth: "max-content" }}>
                    <span style={{
                      width: 18, flexShrink: 0, textAlign: "center",
                      fontSize: 12, fontFamily: "monospace", lineHeight: "20px",
                      color: prefixColor, userSelect: "none",
                    }}>{prefix}</span>
                    <span style={{
                      flex: 1, fontSize: 12, fontFamily: "monospace", lineHeight: "20px",
                      whiteSpace: "pre", color: textColor,
                    }}>{line.content}</span>
                  </Box>
                );
              })}
            </Box>
          ))}
        </Box>
      ))}
    </Box>
  );
}

