/* ── diff2html theme overrides ──────────────────────────────────────────────
   Match font, sizing, and border-radius to the rest of the app.
   Dark mode fully overrides diff2html's light-only palette.
   ──────────────────────────────────────────────────────────────────────────── */

/* Font + sizing — always */
.d2h-wrapper .d2h-file-wrapper {
  font-family: monospace;
  font-size: 12px;
  border-radius: 6px;
  border-color: var(--mantine-color-gray-3);
  overflow: hidden;
}

.d2h-wrapper .d2h-file-header {
  font-family: monospace;
  font-size: 12px;
  border-bottom-color: var(--mantine-color-gray-3);
}

.d2h-wrapper .d2h-file-name {
  font-weight: 600;
}

.d2h-wrapper .d2h-code-linenumber,
.d2h-wrapper .d2h-code-side-linenumber {
  font-size: 11px;
}

.d2h-wrapper .d2h-code-line-ctn,
.d2h-wrapper .d2h-code-line {
  font-family: monospace;
  font-size: 12px;
}

.d2h-wrapper .d2h-tag {
  font-size: 10px;
  border-radius: 3px;
}

/* ── Dark mode ────────────────────────────────────────────────────────────── */

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-wrapper {
  border-color: var(--mantine-color-dark-4);
  background: var(--mantine-color-dark-7);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-header {
  background: var(--mantine-color-dark-6);
  border-bottom-color: var(--mantine-color-dark-4);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-name {
  color: var(--mantine-color-violet-4);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-stats .d2h-lines-added {
  color: var(--mantine-color-green-5);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-stats .d2h-lines-deleted {
  color: var(--mantine-color-red-5);
}

/* File list */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-list-wrapper {
  background: var(--mantine-color-dark-7);
  border-color: var(--mantine-color-dark-4);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-list-header {
  background: var(--mantine-color-dark-6);
  border-bottom-color: var(--mantine-color-dark-4);
  color: var(--mantine-color-gray-4);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-list-line {
  border-bottom-color: var(--mantine-color-dark-5);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-file-list-line a {
  color: var(--mantine-color-violet-4);
}

/* Hunk (@@ header) */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-info {
  background: rgba(59, 130, 246, 0.09);
  color: var(--mantine-color-gray-5);
  border-color: var(--mantine-color-dark-5);
}

/* Line numbers */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-linenumber,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-side-linenumber {
  background: var(--mantine-color-dark-6);
  border-color: var(--mantine-color-dark-4);
  color: var(--mantine-color-gray-6);
}

/* Context lines */
[data-mantine-color-scheme="dark"] .d2h-wrapper td.d2h-code-side-emptyplaceholder,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-emptyplaceholder,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-diff-table tr:not(.d2h-ins):not(.d2h-del):not(.d2h-info) {
  background: var(--mantine-color-dark-7);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-line-ctn,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-line-prefix {
  color: var(--mantine-color-gray-2);
}

/* Added lines */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins.d2h-change,
[data-mantine-color-scheme="dark"] .d2h-wrapper tr.d2h-ins {
  background: rgba(0, 180, 80, 0.13);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins .d2h-code-linenumber,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins .d2h-code-side-linenumber {
  background: rgba(0, 180, 80, 0.18);
  border-color: rgba(0, 180, 80, 0.25);
  color: var(--mantine-color-green-5);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins .d2h-code-line-ctn,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins .d2h-code-line-prefix {
  color: var(--mantine-color-green-3);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins .d2h-code-line-ctn ins,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-ins ins {
  background: rgba(0, 200, 80, 0.3);
  text-decoration: none;
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-added-tag {
  background: var(--mantine-color-green-9);
  color: var(--mantine-color-green-3);
}

/* Deleted lines */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del.d2h-change,
[data-mantine-color-scheme="dark"] .d2h-wrapper tr.d2h-del {
  background: rgba(220, 50, 50, 0.16);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del .d2h-code-linenumber,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del .d2h-code-side-linenumber {
  background: rgba(220, 50, 50, 0.22);
  border-color: rgba(220, 50, 50, 0.3);
  color: var(--mantine-color-red-5);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del .d2h-code-line-ctn,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del .d2h-code-line-prefix {
  color: var(--mantine-color-red-3);
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del .d2h-code-line-ctn del,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-del del {
  background: rgba(220, 60, 60, 0.35);
  text-decoration: none;
}

[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-deleted-tag {
  background: var(--mantine-color-red-9);
  color: var(--mantine-color-red-3);
}

