input.content:
/* ── diff2html theme overrides ──────────────────────────────────────────────
   Structural fixes (both modes) + dark mode via CSS variable overrides.
   ──────────────────────────────────────────────────────────────────────────── */

/* Hide the redundant "Files changed (N)" heading — our SectionBlock has it */
.d2h-wrapper .d2h-file-list-header {
  display: none;
}

/* File header: shrink to match app density, inherit font */
.d2h-wrapper .d2h-file-header {
  height: auto;
  min-height: unset;
  padding: 5px 10px;
  font-family: monospace;
}

/* Filename: match app's xs monospace, not 15px sans-serif */
.d2h-wrapper .d2h-file-name-wrapper {
  font-size: 12px;
  font-family: monospace;
  align-items: center;
}

.d2h-wrapper .d2h-file-name {
  font-size: 12px;
  font-weight: 600;
}

/* Remove the bordered boxes around +N -N stat counts */
.d2h-wrapper .d2h-lines-added,
.d2h-wrapper .d2h-lines-deleted {
  border: none;
  border-radius: 0;
  padding: 0 2px;
  font-size: 11px;
  font-family: monospace;
}

/* "CHANGED" / "ADDED" etc badge: smaller, subtler */
.d2h-wrapper .d2h-tag {
  font-size: 9px;
  font-family: monospace;
  padding: 1px 4px;
  border-radius: 3px;
  opacity: 0.75;
}

/* Code area: 12px monospace throughout */
.d2h-wrapper .d2h-code-line-ctn,
.d2h-wrapper .d2h-code-line,
.d2h-wrapper .d2h-code-linenumber,
.d2h-wrapper .d2h-code-side-linenumber {
  font-family: monospace;
  font-size: 12px;
}

.d2h-wrapper .d2h-file-stats {
  font-size: 11px;
}

/* File list row spacing */
.d2h-wrapper .d2h-file-list {
  font-family: monospace;
  font-size: 12px;
}

/* ── Dark mode — override diff2html's CSS variables ───────────────────────── */

[data-mantine-color-scheme="dark"] .d2h-wrapper {
  --d2h-bg-color:                       var(--mantine-color-dark-7);
  --d2h-border-color:                   var(--mantine-color-dark-4);
  --d2h-dim-color:                      var(--mantine-color-gray-6);
  --d2h-line-border-color:              var(--mantine-color-dark-5);
  --d2h-file-header-bg-color:           var(--mantine-color-dark-6);
  --d2h-file-header-border-color:       var(--mantine-color-dark-4);
  --d2h-empty-placeholder-bg-color:     var(--mantine-color-dark-6);
  --d2h-empty-placeholder-border-color: var(--mantine-color-dark-4);
  --d2h-ins-bg-color:                   rgba(0, 180, 80, 0.12);
  --d2h-ins-border-color:               rgba(0, 180, 80, 0.22);
  --d2h-ins-highlight-bg-color:         rgba(0, 200, 80, 0.28);
  --d2h-ins-label-color:                var(--mantine-color-green-5);
  --d2h-del-bg-color:                   rgba(220, 50, 50, 0.14);
  --d2h-del-border-color:               rgba(220, 50, 50, 0.28);
  --d2h-del-highlight-bg-color:         rgba(220, 60, 60, 0.32);
  --d2h-del-label-color:                var(--mantine-color-red-5);
  --d2h-info-bg-color:                  rgba(59, 130, 246, 0.07);
  --d2h-info-border-color:              rgba(59, 130, 246, 0.18);
}

/* Line number cells: dark background, dim text */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-linenumber,
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-side-linenumber {
  background: var(--mantine-color-dark-6);
  border-color: var(--mantine-color-dark-5);
  color: var(--mantine-color-gray-6);
}

/* Context code text */
[data-mantine-color-scheme="dark"] .d2h-wrapper .d2h-code-line-ctn {
  color: var(--mantine-color-gray-2);
}

/* Info (@@ hunk header) text color */
