/* ── diff2html theme overrides ──────────────────────────────────────────────
   Structural fixes (both modes) + dark mode via CSS variable overrides.
   ──────────────────────────────────────────────────────────────────────────── */

/* Hide the redundant "Files changed (N)" heading — our SectionBlock has it */
.d2h-wrapper .d2h-file-list-header {
  display: none;
}

/* File header: shrink to match app density, inherit font */
.d2h-wrapper .d2h-file-header {
  height: auto;
  min-height: unset;
  padding: 5px 10px;
  font-family: monospace;
}

/* Filename: match app's xs monospace, not 15px sans-serif */
.d2h-wrapper .d2h-file-name-wrapper {
  font-size: 12px;
  font-family: monospace;
  align-items: center;
}

.d2h-wrapper .d2h-file-name {
  font-size: 12px;
  font-weight: 600;
}

/* Remove the bordered boxes around +N -N stat counts */
.d2h-wrapper .d2h-lines-added,
.d2h-wrapper .d2h-lines-deleted {
  border: none;
  border-radius: 0;
  padding: 0 2px;
  font-size: 11px;
  font-family: monospace;
}

/* "CHANGED" / "ADDED" etc badge: smaller, subtler */
