          )}
        </Box>
        <Box style={{ textAlign: "right", flexShrink: 0 }}>
          {fileCount > 0 && <Text size="xs" c="dimmed" ff="monospace">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>}
