/* ── diff2html theme overrides ──────────────────────────────────────────────
   Structural fixes always; dark mode via @media to match colorScheme:"auto".
   Use !important throughout dark section — diff2html's own auto-scheme rules
   have the same specificity and appear later in the bundle.
   ──────────────────────────────────────────────────────────────────────────── */

/* ── Always: structural / font fixes ─────────────────────────────────────── */

/* Hide the redundant "Files changed (N)" heading */
.d2h-file-list-header {
  display: none;
}

/* File header: tighter, inherit font */
.d2h-file-header {
  height: auto !important;
  min-height: unset !important;
  padding: 5px 10px !important;
  font-family: monospace !important;
}

/* Filename text: 12px monospace, not 15px sans-serif */
.d2h-file-name-wrapper {
  font-size: 12px !important;
  font-family: monospace !important;
}
.d2h-file-name {
  font-size: 12px !important;
  font-weight: 600 !important;
}

/* Remove bordered boxes from +N -N stat counts */
.d2h-lines-added,
.d2h-lines-deleted {
  border: none !important;
  border-radius: 0 !important;
  padding: 0 2px !important;
  font-size: 11px !important;
  font-family: monospace !important;
}

/* CHANGED / ADDED / DELETED badge: smaller, no heavy box */
.d2h-tag {
  font-size: 9px !important;
  font-family: monospace !important;
  padding: 1px 4px !important;
  border-radius: 3px !important;
  opacity: 0.7 !important;
}

/* Hide file icons — they don't add much */
.d2h-icon {
  display: none !important;
}

/* Code font throughout */
.d2h-code-line-ctn,
.d2h-code-line,
.d2h-code-linenumber,
.d2h-code-side-linenumber,
.d2h-file-list {
  font-family: monospace !important;
  font-size: 12px !important;
}
.d2h-file-stats {
  font-size: 11px !important;
}

/* ── Dark mode ────────────────────────────────────────────────────────────── */

@media (prefers-color-scheme: dark) {
  /* Whole diff area background */
  .d2h-file-wrapper {
    background-color: #1a1b1e !important; /* mantine dark-7 approx */
    border-color: #373A40 !important;     /* mantine dark-4 approx */
  }

  /* File header */
  .d2h-file-header {
    background-color: #25262b !important; /* mantine dark-6 approx */
    border-bottom-color: #373A40 !important;
  }
  .d2h-file-name {
    color: #b197fc !important; /* mantine violet-4 approx */
  }
  .d2h-file-list-line a {
    color: #b197fc !important;
  }

  /* Tags */
  .d2h-tag {
    background-color: #2c2e33 !important;
    color: #909296 !important;
    border-color: transparent !important;
  }

  /* Hunk @@ header */
  .d2h-info {
    background-color: rgba(59, 130, 246, 0.07) !important;
    border-color: rgba(59, 130, 246, 0.15) !important;
    color: #909296 !important;
  }
  .d2h-info td {
    color: #909296 !important;
  }

  /* Line numbers */
  .d2h-code-linenumber,
  .d2h-code-side-linenumber {
    background-color: #25262b !important;
    border-color: #373A40 !important;
    color: #5c5f66 !important;
  }

  /* Context lines */
  tr:not(.d2h-ins):not(.d2h-del):not(.d2h-info):not(.d2h-change) td,
  .d2h-emptyplaceholder,
  .d2h-code-side-emptyplaceholder {
    background-color: #1a1b1e !important;
  }
  .d2h-code-line-ctn {
    color: #C1C2C5 !important;
  }

  /* Added lines */
  tr.d2h-ins,
  td.d2h-ins {
    background-color: rgba(0, 180, 80, 0.12) !important;
  }
  .d2h-ins .d2h-code-linenumber,
  .d2h-ins .d2h-code-side-linenumber {
    background-color: rgba(0, 180, 80, 0.18) !important;
    border-color: rgba(0, 180, 80, 0.22) !important;
    color: #69db7c !important;
  }
  .d2h-ins .d2h-code-line-ctn {
    color: #b2f2bb !important;
  }
  .d2h-ins ins {
    background-color: rgba(0, 200, 80, 0.28) !important;
    text-decoration: none !important;
  }
  .d2h-ins-label,
  .d2h-lines-added {
    color: #69db7c !important;
  }

  /* Deleted lines */
  tr.d2h-del,
  td.d2h-del {
    background-color: rgba(220, 50, 50, 0.14) !important;
  }
  .d2h-del .d2h-code-linenumber,
  .d2h-del .d2h-code-side-linenumber {
    background-color: rgba(220, 50, 50, 0.20) !important;
    border-color: rgba(220, 50, 50, 0.25) !important;
    color: #ff8787 !important;
  }
  .d2h-del .d2h-code-line-ctn {
    color: #ffc9c9 !important;
  }
  .d2h-del del {
    background-color: rgba(220, 60, 60, 0.34) !important;
    text-decoration: none !important;
  }
  .d2h-del-label,
  .d2h-lines-deleted {
    color: #ff8787 !important;
  }

  /* Changed lines (del+ins pair) — override the light-yellow */
  tr.d2h-change.d2h-del,
  td.d2h-change.d2h-del {
    background-color: rgba(220, 50, 50, 0.14) !important;
  }
  tr.d2h-change.d2h-ins,
  td.d2h-change.d2h-ins {
    background-color: rgba(0, 180, 80, 0.12) !important;
  }
}

